import{_ as a,r as n,o,c as d,b as e,d as r,a as i,e as c}from"./app.521b9759.js";const t={},l=c(`<blockquote><p>系统版本：ubuntu-18.04.4-live-server</p></blockquote><h2 id="root用户" tabindex="-1"><a class="header-anchor" href="#root用户" aria-hidden="true">#</a> root用户</h2><h3 id="sudo-i" tabindex="-1"><a class="header-anchor" href="#sudo-i" aria-hidden="true">#</a> sudo -i</h3><p>默认情况下，系统安装之后只能以普通用户的方式登录，然后通过<code>sudo</code>命令执行一些超级权限命令。不过我们可以通过输入如下命令切换到root用户</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token parameter variable">-i</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后输入当前用户的密码就可以进入到root用户</p><h2 id="root登录" tabindex="-1"><a class="header-anchor" href="#root登录" aria-hidden="true">#</a> root登录</h2><p>要使用root用户登录，需要先设置root用户密码</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">passwd</span> root
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>根据提示输入root用户的密码并确认即可 现在通过<code>su</code>命令输入密码就可以切换到root用户</p><h2 id="ssh远程登录" tabindex="-1"><a class="header-anchor" href="#ssh远程登录" aria-hidden="true">#</a> ssh远程登录</h2><p>Ubuntu默认是不支持ssh远程连接的，如果要支持ssh我们需要先安装<code>openssh-server</code></p><h3 id="安装openssh-server" tabindex="-1"><a class="header-anchor" href="#安装openssh-server" aria-hidden="true">#</a> 安装<code>openssh-server</code></h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> openssh-server
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>正常安装好<code>openssh-server</code>之后，就可以用普通用户的身份进行远程连接了</p><h3 id="远程连接示例" tabindex="-1"><a class="header-anchor" href="#远程连接示例" aria-hidden="true">#</a> 远程连接示例</h3><blockquote><p>假设目标主机的</p><ul><li>ip为<code>192.168.222.133</code></li><li>用户名为<code>cnbank</code></li></ul></blockquote><p>执行如下命令即可实现远程连接</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ssh</span> cnbank@192.168.222.133
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><em>如果前面已经设置了root用户的密码，试试通过root用户远程连接，是不是不能登录？</em></p></blockquote><h3 id="启用root用户远程连接" tabindex="-1"><a class="header-anchor" href="#启用root用户远程连接" aria-hidden="true">#</a> 启用root用户远程连接</h3><p>上述简单操作之后，可以实现以普通用户的身份进行远程登录，但是无法实现以root用户的身份登录，如果要实现root用户连接还需要做一点配置修改</p><ul><li><strong>修改ssh配置文件</strong></li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">vim</span> /etc/ssh/sshd_config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>找到<code>PermitRootLogin</code>配置项，取消注释并修改参数值为<code>yes</code>，保存配置文件</p><blockquote><ul><li><code>vi</code>、<code>vim</code>命令打开文本后，输入<code>i</code>可进入编辑模式，<code>:q</code>可退出</li><li>编辑文本后，点击<code>ESC</code>退出编辑模式，输入<code>:wq</code>命令可保存并退出，<code>:q!</code>强制退出不保存文本</li></ul></blockquote><ul><li><strong>重启ssh服务</strong></li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">service</span> <span class="token function">ssh</span> restart
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>现在目标主机就支持root用户远程连接了。</p><h2 id="相关链接" tabindex="-1"><a class="header-anchor" href="#相关链接" aria-hidden="true">#</a> 相关链接</h2>`,30),u={href:"https://www.jianshu.com/p/0e69b4e73a8c",title:"Ubuntu 启用允许ssh远程登录root用户",target:"_blank",rel:"noopener noreferrer"};function h(p,b){const s=n("ExternalLinkIcon");return o(),d("div",null,[l,e("p",null,[e("a",u,[r("Ubuntu 启用允许ssh远程登录root用户"),i(s)])])])}const m=a(t,[["render",h],["__file","ubuntu-basic-operate.html.vue"]]);export{m as default};
